// // This module is designed to capture the state of a 10-bit input switch (sw) on the falling edge of a clock signal and outputs a 16-bit wide signal (portout). The output combines 5 trailing zero bits followed by the 10 bits from the input switch, effectively zero-padding the input to create a wider data output.
module top_module(sw, clock, portout);input [9:0]sw;
input clock;
output reg [15:0]portout;

always @(posedge clock)
	portout <= {5'b0,sw};endmodule
